/**
 * Split a multi-part question into individual questions.
 * "Revenue by region and also top 5 customers?" → ["Revenue by region", "top 5 customers"]
 */
export function splitQuestions(input) {
  const text = input.trim();
  const parts = text
    .split(/\?\s*(?:and also|and|also|additionally|plus)\s+/i)
    .map(p => p.replace(/\?+$/, '').trim())
    .filter(p => p.length > 3);
  return parts.length <= 1 ? [text.replace(/\?+$/, '').trim()] : parts;
}
